def calculate_rectangle_area(width, height):
    assert isinstance(width, (int, float)), "Width must be a number."
    assert isinstance(height, (int, float)), "Height must be a number."
    assert width > 0, "Width must be positive."
    assert height > 0, "Height must be positive."

    return width * height

if __name__ == "__main__":
    # Geçerli girdiler
    print(f"Area (5, 10): {calculate_rectangle_area(5, 10)}")
    print(f"Area (2.5, 4.0): {calculate_rectangle_area(2.5, 4.0)}")

    # Geçersiz girdiler - AssertError beklenen durumlar
    try:
        calculate_rectangle_area("5", 10)
    except AssertionError as e:
        print(f"Hata yakalandı: {e}")

    try:
        calculate_rectangle_area(5, -10)
    except AssertionError as e:
        print(f"Hata yakalandı: {e}")

    try:
        calculate_rectangle_area(0, 10)
    except AssertionError as e:
        print(f"Hata yakalandı: {e}")

    try:
        calculate_rectangle_area(None, 10)
    except AssertionError as e:
        print(f"Hata yakalandı: {e}")
